public int findMinMaximumValue(int[] nums) {
    int result = nums[0], sum = nums[0];
    for (int i = 1; i < nums.length; i++) {
        sum += nums[i];
        result = Math.max(result, (sum + i) / (i + 1));
    }
    return result;
}
```

